import{_ as a,o,c as t,a2 as r}from"./chunks/framework.BWuWLRhz.js";const p="/images/the-apple-game-how-good-person-are-you/Apple-3x2.png",n="/images/the-apple-game-how-good-person-are-you/Apple-Range.png",s="/images/the-apple-game-how-good-person-are-you/pinit_fg_en_rect_gray_20.png",A=JSON.parse('{"title":"The Apple Game: How Good a Person Are You?","description":"","frontmatter":{"title":"The Apple Game: How Good a Person Are You?","titleZh":"苹果游戏:你是多好的人","date":"2013-08-30T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/08/the-apple-game-how-good-person-are-you.html","slug":"the-apple-game-how-good-person-are-you"},"headers":[],"relativePath":"posts/the-apple-game-how-good-person-are-you.md","filePath":"posts/the-apple-game-how-good-person-are-you.md","lastUpdated":1782886257000}'),h={name:"posts/the-apple-game-how-good-person-are-you.md"};function l(g,e,i,d,m,b){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="苹果游戏-你是多好的人-·-the-apple-game-how-good-a-person-are-you" tabindex="-1">苹果游戏:你是多好的人 · The Apple Game: How Good a Person Are You? <a class="header-anchor" href="#苹果游戏-你是多好的人-·-the-apple-game-how-good-a-person-are-you" aria-label="Permalink to &quot;苹果游戏:你是多好的人 · The Apple Game: How Good a Person Are You?&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/08/the-apple-game-how-good-person-are-you.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/08/the-apple-game-how-good-person-are-you.html</a> · 2013-08-30</p></blockquote><p>我想向你介绍一个我和朋友们玩了好多年的游戏。其实也不算游戏——更像是个练习。目的是让「你是个好人吗?」这个问题多一点深度。玩法是这样的:把一个人当成一个苹果,分三层深度——</p><p><a href="https://1.bp.blogspot.com/-bOJJ3k7l54w/UiDJT5mTjgI/AAAAAAAAFL8/nU2xIvylDVY/s1600/Apple+3x2.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>思路是在这三层的每一层上,简单把一个人标记为「好」或「坏」,从而形成一份「苹果档案」——从里到外快速评估他的善良程度。关于这三层的更多细节:</p><h2 id="第-1-层-苹果皮" tabindex="-1"><strong>第 1 层)苹果皮</strong> <a class="header-anchor" href="#第-1-层-苹果皮" aria-label="Permalink to &quot;**第 1 层)苹果皮**&quot;">​</a></h2><p>**定义:**你给人的第一印象</p><p>**谁认识你的皮:**所有跟你打过交道的人,从你买东西时的收银员(最外层的表面)到从没真正深入了解过的同事(更往里一点,但仍算作皮)。</p><p><strong>判断你的皮是好是坏的问题:</strong></p><p>– 人们初次见你时,通常会喜欢你、在你身边感到自在吗? – 几乎不了解你的人会觉得你是个好人吗? – 人们会用「友善」来形容你吗? – 你在公共场合表现得让人愉快吗? – 你对服务员、出租车司机和收银员几乎总是很客气吗?</p><p><strong>如果这些问题多数回答「是」,你的皮是好的。否则,你的皮是坏的。</strong></p><h2 id="" tabindex="-1">** <a class="header-anchor" href="#" aria-label="Permalink to &quot;**&quot;">​</a></h2><p>第 2 层)苹果肉**</p><p>**定义:**人们了解你之后,你是什么样的</p><p>**谁认识你的肉:**朋友、家人、伴侣,以及生活中其他相当了解你的人。</p><p><strong>判断你的肉是好是坏的问题:</strong></p><p>– 你在别人背后谈论他们的方式,是否常常和当面谈论时非常不一样? – 如果有人在你在乎的人不在场时说他坏话,你是否常常保持沉默(而不是站出来为对方说话)? – 熟悉你的人会说你有时相当小心眼吗? – 熟悉你的人会说你有时相当爱评判别人吗? – 认识的人遇到倒霉事时,你是否常有幸灾乐祸的感觉? – 和熟人一对一吃饭时,你是否可以毫无顾忌地在超过 50% 的时间里都在聊自己? – 你在保守秘密方面做得不太好吗? – 你在讲述自己生活中的故事时,是否有时会夸大或撒谎? – 你是否不太擅长归还借来的东西或及时还钱给别人?</p><p><strong>如果这些问题大多数回答「否」,你的肉是好的。否则,你的肉是坏的。</strong></p><h2 id="第-3-层-苹果核" tabindex="-1"><strong>第 3 层)苹果核</strong> <a class="header-anchor" href="#第-3-层-苹果核" aria-label="Permalink to &quot;**第 3 层)苹果核**&quot;">​</a></h2><p>**定义:**你内心深处是什么样的</p><p>**谁认识你的核:**对某些人来说,是他们最亲密的朋友、家人或伴侣。对另一些人来说,只有他自己知道自己的核是什么样的。</p><p><strong>判断你的核是好是坏的问题:</strong></p><p>– 想象有一个按钮,一旦按下,地球上某处会有 1000 个陌生人立刻毙命,但同时你的一个职业梦想会成真,或者你会遇到真爱。没有人会知道是你按的。你有整整一个小时坐在按钮前思考这个决定。一小时结束时,你会按吗? – 你会仅仅因为“作恶让你爽”就去残忍待人吗? – 你对身边最弱势的人是不是最刻薄的? – 你在乎的人遭遇不幸时,你是不是很少能真正共情? – 你和朋友家人相处时,是不是通常让他们对自己的感觉更糟? – 最亲近你的人会同意“说到底,她真的只在乎自己”这句评价吗?你自己会同意这个评价吗?</p><p><strong>如果这些问题的答案大多是“不”,那你的核心是好的。反之则是坏的。</strong></p><p>下面这张图大致描绘了你生活中的各种人分别了解你到什么深度:</p><p><a href="https://1.bp.blogspot.com/-tE0dvX05q6w/UiDDV5eJSkI/AAAAAAAAFLs/OaFAH67Ov2Q/s1600/Apple+Range.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>这些范围之所以是范围,不仅是因为同一类里的不同人对你了解的深度不同,还因为有些人比其他人更开放、更愿意“让别人走进来”。所以 Tommy 的“比较好的朋友”可能比 Jenny 最亲密的朋友还要更了解他,因为 Tommy 对朋友比 Jenny 更开放。</p><p>不管怎么说,最后的结果是一共有八种可能的“苹果人格”。要得出你或别人的苹果人格,只需要给三层每一层标上“好”或“坏”,然后按顺序说出来(皮、肉、核)。所以皮好、肉坏、核好的人,就是一个「好—坏—好」。</p><p>我们来一个个说说这些人格:</p><h2 id="_1-好—好—好" tabindex="-1"><strong>1) 好—好—好</strong> <a class="header-anchor" href="#_1-好—好—好" aria-label="Permalink to &quot;**1) 好—好—好**&quot;">​</a></h2><p><strong>他们是啥样:</strong> 里里外外都是圣人;除了「坏—好—好」以外的所有人都让他们有点不自在;他们完全低估了坏人到底能有多坏。</p><p><strong>他们的优点:</strong> 这个世界需要一些这样的人来把一切维系住;他们值得高度信任。</p><p><strong>他们的缺点:</strong> 他们有可能把房间里的乐趣全部吸干;他们看不惯的东西太多。</p><h2 id="_2-坏—好—好" tabindex="-1"><strong>2) 坏—好—好</strong> <a class="header-anchor" href="#_2-坏—好—好" aria-label="Permalink to &quot;**2) 坏—好—好**&quot;">​</a></h2><p><strong>他们是啥样:</strong> 一开始把新认识的人吓退,等你真正了解他们之后,才发现他们简直好得没话说。「好—好—好」的人喜欢交一个「坏—好—好」当象征性的朋友,好让身边人时刻保持警觉。</p><p><strong>他们的优点:</strong> 靠谱到极致;既讨厌虚伪也讨厌小气;人们通常很尊重他们;他们能当出色的领袖。</p><p><strong>他们的缺点:</strong> 他们的自我可能有点太享受那种“表面冷淡内心美好”的人设了。</p><h2 id="_3-好—坏—好" tabindex="-1"><strong>3) 好—坏—好</strong> <a class="header-anchor" href="#_3-好—坏—好" aria-label="Permalink to &quot;**3) 好—坏—好**&quot;">​</a></h2><p>**他们的特点:**当新认识的人夸他们<em>人真好</em>的时候,他们的朋友会忍不住偷笑;他们通常和一堆其他的 GOOD-BAD-GOOD 混在一起;他们经常觉得自己比实际上要更坏。</p><p>**他们的优点:**通常很有趣、也经常挺搞笑;社交能力一流。</p><p>**他们的糟糕之处:**可能又假又小气,但也没到多严重的地步。</p><h2 id="_4-bad-bad-good" tabindex="-1"><strong>4) BAD-BAD-GOOD</strong> <a class="header-anchor" href="#_4-bad-bad-good" aria-label="Permalink to &quot;**4) BAD-BAD-GOOD**&quot;">​</a></h2><p>**他们的特点:**他们让不少人望而生畏,让另一些人敬而远之,但他们的朋友觉得他们是最棒的,并且会拼死为他们辩护。他们的朋友大多也是 BAD-BAD-GOOD,里面点缀着一些 GOOD-BAD-GOOD 和一些 BAD-BAD-BAD。 **他们的优点:**他们是个混蛋,但至少是个心地善良的混蛋。</p><p>**他们的糟糕之处:**他们是个混蛋。</p><h2 id="_5-good-good-bad" tabindex="-1"><strong>5) GOOD-GOOD-BAD</strong> <a class="header-anchor" href="#_5-good-good-bad" aria-label="Permalink to &quot;**5) GOOD-GOOD-BAD**&quot;">​</a></h2><p>**他们的特点:**危险人物;他们能赢得很多人的心,最后又伤害很多人;他们和 GOOD-GOOD-GOOD 交朋友,然后和他们闹得很难看地翻脸。</p><p>**他们的优点:**在 Bad Core 类人里,至少他们大部分时间是在让世界变得更好;非常适合从政。</p><p>**他们的糟糕之处:**他们伤害的往往是离他们最近的人;他们极其擅长操控别人。</p><h2 id="_6-bad-good-bad" tabindex="-1"><strong>6) BAD-GOOD-BAD</strong> <a class="header-anchor" href="#_6-bad-good-bad" aria-label="Permalink to &quot;**6) BAD-GOOD-BAD**&quot;">​</a></h2><p>**他们的特点:**这是一种奇怪而罕见的类型,通常发生在一个不那么好的人小心翼翼地经营自己人设的时候;他们经常处于妄想之中,以为自己是 BAD-GOOD-GOOD(“别人以为我是个混蛋,但了解我的人知道我是个很棒的人”),并且否认自己 Bad Core 的一切痕迹;他们伤透很多人的心。</p><p>**他们的优点:**很适合在残酷的行业里混出头(他们的坏皮可以带来足够的威慑,他们的好肉可以建立一个庞大的信任网络,而他们的坏核可以一心一意不择手段地追求个人上位,必要时把人卖了)。</p><p>**他们的糟糕之处:**他们就是挺烂的人。</p><h2 id="_7-good-bad-bad" tabindex="-1"><strong>7) GOOD-BAD-BAD</strong> <a class="header-anchor" href="#_7-good-bad-bad" aria-label="Permalink to &quot;**7) GOOD-BAD-BAD**&quot;">​</a></h2><p>**他们的特点:**那种谁都爱和他玩、结果发现原来是个大混蛋的朋友。和 GOOD-BAD-GOOD 一见如故地打得火热,然后大量翻脸收场。</p><p>**他们的优点:**去《娇妻真人秀》(Real Housewives) 当演员简直绝了。</p><p>**他们的糟糕之处:**这一群里最假的。</p><h2 id="_8-bad-bad-bad" tabindex="-1"><strong>8) BAD-BAD-BAD</strong> <a class="header-anchor" href="#_8-bad-bad-bad" aria-label="Permalink to &quot;**8) BAD-BAD-BAD**&quot;">​</a></h2><p>**他们的特点:**就是一个老派的坏人。有时候朋友会试图编个故事,说他们的 BAD-BAD-BAD 朋友其实是 BAD-BAD-GOOD,但没人真的信。他们不太理解 Good Core 类的人,同时鄙视 GOOD-GOOD-BAD 和 BAD-GOOD-BAD——因为这两种人都以为自己、并且想向全世界表演自己比 BAD-BAD-BAD 更高尚——BBB 一眼看穿。</p><p>**他们的优点:**他们既不虚伪也不自欺;经常能成为出色的脱口秀演员;非常适合黑手党。</p><p>**他们的糟糕之处:**你还真的需要问他们哪里糟糕吗?</p><h2 id="那么-你是哪一种呢-你的朋友和家人们又是哪一种" tabindex="-1">那么……你是哪一种呢?你的朋友和家人们又是哪一种? <a class="header-anchor" href="#那么-你是哪一种呢-你的朋友和家人们又是哪一种" aria-label="Permalink to &quot;那么……你是哪一种呢?你的朋友和家人们又是哪一种?&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一发布就会寄到你手上。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面-。" tabindex="-1">想支持 Wait But Why,请访问我们的**<a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a>**。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面-。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的**[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇文章,不妨看看:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:为什么你该停止在意别人怎么想</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生是一幅画,但你活在一个像素里</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">你八成身处其中的 10 种怪异友谊</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/08/the-apple-game-how-good-person-are-you.html&amp;description=The%20Apple%20Game:%20How%20Good%20a%20Person%20Are%20You?" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p>',69)])])}const D=a(h,[["render",l]]);export{A as __pageData,D as default};
